using ByteForge.Toolkit.CommandLine;
using System.Reflection;

// Advanced builder configuration
public class AdvancedProgram
{
    public static async Task<int> Main(string[] args)
  {
   var builder = new RootCommandBuilder("Advanced CLI Tool")
        {
          EnableHelp = true,              // Built-in help support
        EnableEnvironmentVariables = true,    // [env:VAR_NAME] support
    EnableParseDirective = true,   // [parse] diagnostic
         EnableSuggestDirective = true,    // [suggest] autocomplete
  EnableTypoCorrections = true,         // Suggest corrections
            EnableParseErrorReporting = true,     // Detailed errors
            EnableExceptionHandler = true,        // Exception handling
            EnableCancellation = true,      // Ctrl+C support
            EnableCaseSensitivity = false,        // Case-insensitive
          EnableParameterExplanation = true     // Show parsed parameters
        };

        // Add custom banner
   builder.BannerAction = () =>
        {
            Console.ForegroundColor = ConsoleColor.Cyan;
       Console.WriteLine(@"
    ╔═══════════════════════════════════════╗
    ║  Advanced CLI Tool v2.0               ║
  ║  Enterprise Command Line Framework    ║
  ╚═══════════════════════════════════════╝
            ");
       Console.ResetColor();
        };

   // Add multiple assemblies
        builder.AddAssembly(Assembly.GetExecutingAssembly());
  builder.AddAssembly("Plugins.dll");
        builder.AddAssembly("Extensions.dll");

      // Add global options for application-wide settings
        builder.AddGlobalOption(new GlobalOption(
            "debug",
       "Enable debug mode with detailed logging",
            () => 
            {
         Environment.SetEnvironmentVariable("DEBUG", "1");
    Console.WriteLine("[DEBUG] Debug mode enabled");
          },
       expectsValue: false,
      "d"));

        builder.AddGlobalOption(new GlobalOption(
   "quiet",
         "Suppress non-essential output",
     () => 
        {
 Console.SetOut(System.IO.TextWriter.Null);
       },
   expectsValue: false,
            "q"));

        builder.AddGlobalOption(new GlobalOption(
       "log-file",
            "Write logs to specified file",
          (filePath) =>
            {
 var logStream = new System.IO.StreamWriter(filePath, append: true);
     Console.SetOut(logStream);
         Console.WriteLine($"[{DateTime.Now}] Log session started");
     },
            expectsValue: true,
         "log", "l"));

        builder.AddGlobalOption(new GlobalOption(
            "color",
     "Enable/disable colored output",
        (value) =>
   {
         if (bool.TryParse(value, out bool enabled))
      {
    if (!enabled)
            Console.ResetColor();
  }
            },
            expectsValue: true));

     // Build and parse
        var parser = builder.Build();
   var result = parser.Parse(args);

        return await result.Invoke();
    }
}

