using ByteForge.Toolkit.CommandLine;
using System.CommandLine;

public class ParseResultExample
{
    public static async Task<int> Main(string[] args)
    {
        var builder = new RootCommandBuilder("Parse Result Demo");
        builder.AddAssembly(typeof(ParseResultExample).Assembly);

        var parser = builder.Build();
        var result = parser.Parse(args);

        // Check for parsing errors
 if (result.Errors.Any())
        {
    Console.ForegroundColor = ConsoleColor.Red;
            Console.WriteLine("❌ Parsing failed with the following errors:");
            foreach (var error in result.Errors)
                Console.WriteLine($"  • {error}");
            Console.ResetColor();
            return 1;
        }

        // Get command information
        var command = result.CommandResult.Command;
        Console.WriteLine($"Executing command: {command.Name}");
   Console.WriteLine($"Description: {command.Description}");

        // Invoke the command
        return await result.Invoke();
    }
}

// Advanced example with custom result handling
public class CustomResultHandling
{
    public static int Main(string[] args)
    {
        var builder = new RootCommandBuilder("Custom Result Handler");

      // Define options we want to query
        var inputOption = new Option<string>("--input", "Input file");
      var outputOption = new Option<string>("--output", "Output file");

builder.AddAssembly(typeof(CustomResultHandling).Assembly);
        var parser = builder.Build();
        var result = parser.Parse(args);

        // Query specific option values
     var inputValue = result.GetValueForOption(inputOption);
      var outputValue = result.GetValueForOption(outputOption);

     if (inputValue != null)
 Console.WriteLine($"Input: {inputValue}");
    if (outputValue != null)
          Console.WriteLine($"Output: {outputValue}");

   // Check for specific errors
        var hasRequiredOptionError = result.Errors
 .Any(e => e.ToString().Contains("Required"));

    if (hasRequiredOptionError)
   {
            Console.WriteLine("Missing required options!");
       return 1;
   }

        return result.Invoke();
    }
}

// Error recovery example
public class ErrorRecoveryExample
{
    public static async Task<int> Main(string[] args)
{
        var builder = new RootCommandBuilder("Error Recovery App");
        builder.EnableParseErrorReporting = true;
     builder.EnableTypoCorrections = true;

 builder.AddAssembly(typeof(ErrorRecoveryExample).Assembly);

     var parser = builder.Build();
        var result = parser.Parse(args);

   if (result.Errors.Any())
      {
     Console.WriteLine("Errors encountered during parsing:");

            foreach (var error in result.Errors)
            {
 Console.WriteLine($"\n❌ {error}");

                // Provide helpful suggestions
                if (error.ToString().Contains("Unrecognized"))
      {
     Console.WriteLine("Did you mean one of these?");
       // System.CommandLine might suggest alternatives
          }
      }

        Console.WriteLine("\nUse --help for usage information");
 return 1;
        }

        return await result.Invoke();
    }
}

