// Dynamic message updates
public class DynamicSpinnerMessages
{
    public static void Main()
    {
        var spinner = new ConsoleSpinner("Starting");
        spinner.Color = ConsoleColor.Yellow;

  try
        {
            spinner.Start();

for (int i = 1; i <= 10; i++)
            {
      spinner.Message = $"Processing item {i}/10";
Thread.Sleep(500);
    }

            spinner.Color = ConsoleColor.Green;
          spinner.Message = "Finalizing";
         Thread.Sleep(1000);
        }
        finally
        {
 spinner.Stop();
        }

        Console.WriteLine("✓ Complete!");
    }
}

