// Progress with dynamic messages
public class DynamicProgress
{
    public static async Task Main()
    {
        var progress = new ProgressSpinner("Initializing");

   try
      {
    await Task.Delay(1000);

     progress.Message = "Loading configuration";
          await Task.Delay(1000);

   progress.Message = "Connecting to services";
   await Task.Delay(1500);

            progress.Message = "Starting application";
            await Task.Delay(1000);
        }
        finally
        {
            progress.Dispose();
        }

   Console.WriteLine("✓ Application started!");
    }
}

