");
  Console.ResetColor();
     };

        // Global options
  builder.AddGlobalOption(new GlobalOption(
         "verbose", 
         "Enable detailed logging",
      () => Environment.SetEnvironmentVariable("VERBOSE", "1"),
         expectsValue: false,
            "v"));

        builder.AddGlobalOption(new GlobalOption(
            "config",
       "Configuration file path",
         (path) => LoadConfig(path),
     expectsValue: true,
            "c"));

        // Load commands from assembly
    builder.AddAssembly(Assembly.GetExecutingAssembly());

        var parser = builder.Build();
        var result = parser.Parse(args);

        if (result.Errors.Any())
        {
            Console.ForegroundColor = ConsoleColor.Red;
            foreach (var error in result.Errors)
    Console.WriteLine($"Error: {error}");
     Console.ResetColor();
            return 1;
     }

        return await result.Invoke();
    }

 private static void LoadConfig(string path)
    {
        Console.WriteLine($"Loading configuration from: {path}");
    }
}

// ═══════════════════════════════════════════════════════════════
// Database Commands (Command Group)
// ═══════════════════════════════════════════════════════════════

[Command("database", "Database management commands", "db")]
public class DatabaseCommands
{
    [Command("backup", "Create database backup")]
    public async Task<int> Backup(
        [Option("Database connection string")] string connectionString,
   [Option("Backup file path")] string outputPath,
        [Option("Compression level (0-9)")] int compression = 5)
    {
   using (new ProgressSpinner($"Creating backup"))
        {
 Console.WriteLine($"Connection: {connectionString}");
 Console.WriteLine($"Output: {outputPath}");
            Console.WriteLine($"Compression: {compression}");

            await Task.Delay(3000); // Simulate backup
        }

        Console.WriteLine($"✓ Backup created: {outputPath}");
        return 0;
    }

    [Command("restore", "Restore database from backup")]
    public async Task<int> Restore(
        [Option("Database connection string")] string connectionString,
        [Option("Backup file path")] string backupPath,
        [Option("Overwrite existing database")] bool force = false)
    {
        if (!force)
        {
            Console.Write("This will overwrite the database. Continue? (y/n): ");
     if (Console.ReadLine()?.ToLower() != "y")
       {
    Console.WriteLine("Restore cancelled");
       return 0;
            }
     }

        using (new ProgressSpinner("Restoring database"))
     {
       await Task.Delay(4000); // Simulate restore
        }

        Console.WriteLine("✓ Database restored successfully!");
        return 0;
    }

    [Command("migrate", "Run database migrations")]
  public async Task<int> Migrate(
        [Option("Database connection string")] string connectionString,
        [Option("Target migration version")] string? targetVersion = null,
    [Option("Dry run without applying changes")] bool dryRun = false)
    {
      Console.WriteLine($"Migration mode: {(dryRun ? "Dry Run" : "Apply")}");

        using (new ProgressSpinner("Running migrations"))
        {
            await Task.Delay(2500);
   }

        Console.WriteLine("✓ Migrations completed!");
        return 0;
    }
}

// ═══════════════════════════════════════════════════════════════
// File Processing Commands (Command Group)
// ═══════════════════════════════════════════════════════════════

[Command("file", "File processing operations")]
public class FileCommands
{
    [Command("convert", "Convert file format")]
    public async Task<int> Convert(
        [Option("Input file path")] string input,
     [Option("Output file path")] string output,
        [Option("Target format")] FileFormat format,
   [Option("Encoding")] string encoding = "UTF-8")
    {
        Console.WriteLine($"Converting: {input} → {output}");
        Console.WriteLine($"Format: {format}");
        Console.WriteLine($"Encoding: {encoding}");

   using (new ProgressSpinner("Converting file"))
        {
       await Task.Delay(2000);
        }

  Console.WriteLine("✓ Conversion complete!");
        return 0;
    }

    [Command("validate", "Validate file integrity")]
    public void Validate(
        [Option("File path to validate")] string path,
        [Option("Validation type")] ValidationType type = ValidationType.Checksum)
    {
   Console.WriteLine($"Validating: {path}");
      Console.WriteLine($"Type: {type}");

        using (new ConsoleSpinner("Validating"))
      {
    Thread.Sleep(1500);
   }

  Console.WriteLine("✓ File is valid!");
  }

    [Command("compress", "Compress files")]
    public void Compress(
        [Option("Input file or directory")] string input,
    [Option("Output archive path")] string output,
        [Option("Compression algorithm")] CompressionType algorithm = CompressionType.GZip,
        [Option("Compression level (0-9)")] int level = 6)
    {
        Console.WriteLine($"Compressing: {input}");
        Console.WriteLine($"Output: {output}");
        Console.WriteLine($"Algorithm: {algorithm}, Level: {level}");

        using (new ConsoleSpinner($"Compressing with {algorithm}"))
        {
            Thread.Sleep(2000);
     }

     Console.WriteLine("✓ Compression complete!");
    }
}

// ═══════════════════════════════════════════════════════════════
// Standalone Commands (Static Methods)
// ═══════════════════════════════════════════════════════════════

public class StandaloneCommands
{
    [Command("version", "Display version information", "ver", "v")]
    public static void ShowVersion()
    {
  var version = Assembly.GetExecutingAssembly().GetName().Version;
      var product = Assembly.GetExecutingAssembly()
          .GetCustomAttribute<AssemblyProductAttribute>()?.Product;
        var company = Assembly.GetExecutingAssembly()
            .GetCustomAttribute<AssemblyCompanyAttribute>()?.Company;

        Console.WriteLine($"{product} v{version}");
        Console.WriteLine($"© {DateTime.Now.Year} {company}");
    }

    [Command("info", "Display system information")]
  public static void ShowInfo()
    {
 Console.WriteLine("System Information:");
    Console.WriteLine($"  OS: {Environment.OSVersion}");
        Console.WriteLine($"  .NET: {Environment.Version}");
        Console.WriteLine($"  Processors: {Environment.ProcessorCount}");
        Console.WriteLine($"  64-bit: {Environment.Is64BitOperatingSystem}");
    }
}

